class Solution:
    def unhappyFriends(self, n, preferences, pairs):
        partner = {}
        for x, y in pairs:
            partner[x] = y
            partner[y] = x
        pref_index = [dict() for _ in range(n)]
        for i in range(n):
            for pos, p in enumerate(preferences[i]):
                pref_index[i][p] = pos
        unhappy_people = set()
        for x in range(n):
            y = partner[x]
            for u in range(n):
                if u == x or u == y:
                    continue
                v = partner[u]
                if pref_index[x][u] < pref_index[x][y] and pref_index[u][x] < pref_index[u][v]:
                    unhappy_people.add(x)
                    break
        return len(unhappy_people)

