var unhappyFriends = function(n, preferences, pairs) {
    const partner = new Array(n);
    for (const [x, y] of pairs) {
        partner[x] = y;
        partner[y] = x;
    }
    const rank = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        for (let pos = 0; pos < preferences[i].length; pos++) {
            rank[i][preferences[i][pos]] = pos;
        }
    }
    let unhappy = 0;
    for (let x = 0; x < n; x++) {
        const y = partner[x];
        for (const u of preferences[x]) {
            if (rank[x][u] >= rank[x][y]) break;
            const v = partner[u];
            if (rank[u][x] < rank[u][v]) {
                unhappy++;
                break;
            }
        }
    }
    return unhappy;
};
